{
  "sentences": [
    {
      "text": "你來台灣多久了？",
      "pinyin": "Nǐ lái Táiwān duō jiǔ le?",
      "pinyin_numeric": "ni3 lai2 Tai2wan1 duo1 jiu3 le0",
      "translation_en": "How long have you been in Taiwan?",
      "translation_ko": "대만에 온 지 얼마나 되었어요?"
    },
    {
      "text": "我來台灣三個月了。",
      "pinyin": "Wǒ lái Táiwān sān ge yuè le.",
      "pinyin_numeric": "wo3 lai2 Tai2wan1 san1 ge0 yue4 le0",
      "translation_en": "I have been in Taiwan for three months.",
      "translation_ko": "대만에 온 지 세 달 되었어요."
    },
    {
      "text": "我從美國來，在台灣學中文。",
      "pinyin": "Wǒ cóng Měiguó lái, zài Táiwān xué Zhōngwén.",
      "pinyin_numeric": "wo3 cong2 Mei3guo2 lai2, zai4 Tai2wan1 xue2 Zhong1wen2",
      "translation_en": "I come from the United States and am studying Chinese in Taiwan.",
      "translation_ko": "저는 미국에서 왔고, 대만에서 중국어를 배우고 있어요."
    },
    {
      "pinyin": "Wǒ shì xuéshēng, zài Táiwān liúxué.",
      "pinyin_numeric": "wo3 shi4 xue2sheng1, zai4 Tai2wan1 liu2xue2",
      "translation_en": "I am a student studying abroad in Taiwan.",
      "translation_ko": "저는 학생이고, 대만에서 유학 중이에요.",
      "text": "我是學生，在台灣留學。"
    },
    {
      "pinyin": "Wǒ de gùxiāng shì yī ge xiǎo chéngshì.",
      "pinyin_numeric": "wo3 de0 gu4xiang1 shi4 yi1 ge0 xiao3 cheng2shi4",
      "translation_en": "My hometown is a small city.",
      "translation_ko": "제 고향은 작은 도시예요.",
      "text": "我的故鄉是一個小城市。"
    },
    {
      "pinyin": "Wǒ xiǎng xué Zhōngwén, yīnwèi wǒ xǐhuān Táiwān de wénhuà.",
      "pinyin_numeric": "wo3 xiang3 xue2 Zhong1wen2, yin1wei4 wo3 xi3huan1 Tai2wan1 de0 wen2hua4",
      "translation_en": "I want to learn Chinese because I like Taiwanese culture.",
      "translation_ko": "저는 대만 문화를 좋아해서 중국어를 배우고 싶어요.",
      "text": "我想學中文，因為我喜歡台灣的文化。"
    },
    {
      "pinyin": "Wǒ de gōngzuò shì gōngchéngshī, dàn wǒ xiànzài zài shàngkè.",
      "pinyin_numeric": "wo3 de0 gong1zuo4 shi4 gong1cheng2shi1, dan4 wo3 xian4zai4 zai4 shang4ke4",
      "translation_en": "My job is an engineer, but I am currently taking classes.",
      "translation_ko": "제 직업은 엔지니어인데, 지금은 수업을 듣고 있어요.",
      "text": "我的工作是工程師，但我現在在上課。"
    },
    {
      "pinyin": "Nǐ cóng nǎlǐ lái? Wǒ cóng Rìběn lái.",
      "pinyin_numeric": "ni3 cong2 na3li3 lai2? wo3 cong2 Ri4ben3 lai2.",
      "translation_en": "Where are you from? I am from Japan.",
      "translation_ko": "어디에서 오셨어요? 저는 일본에서 왔어요.",
      "text": "你從哪裡來？我從日本來。"
    },
    {
      "pinyin": "Wǒ xīwàng jiānglái néng shuō liúlì de Zhōngwén.",
      "pinyin_numeric": "wo3 xi1wang4 jiang1lai2 neng2 shuo1 liu2li4 de0 Zhong1wen2.",
      "translation_en": "I hope to speak fluent Chinese in the future.",
      "translation_ko": "저는 장래에 중국어를 유창하게 말할 수 있기를 바라요.",
      "text": "我希望將來能說流利的中文。"
    },
    {
      "pinyin": "Wǒ yǐjīng xué Zhōngwén bàn nián le, jìnbù hěn duō.",
      "pinyin_numeric": "wo3 yi3jing1 xue2 Zhong1wen2 ban4 nian2 le, jin4bu4 hen3 duo1.",
      "translation_en": "I have been studying Chinese for half a year and have made a lot of progress.",
      "translation_ko": "저는 중국어를 반 년째 배우고 있는데, 많이 발전했어요.",
      "text": "我已經學中文半年了，進步很多。"
    }
  ]
}
